// src/components/SplashCursor.jsx (rewritten in plain JavaScript with gradient logic)
'use client';
import { useEffect, useRef } from 'react';

/**
 * Full-screen WebGL splash with a left-to-right gradient from #57B2B6 to white.
 */
export default function SplashCursor({
  SIM_RESOLUTION = 128,
  DYE_RESOLUTION = 1440,
  CAPTURE_RESOLUTION = 512,
  DENSITY_DISSIPATION = 3.5,
  VELOCITY_DISSIPATION = 2,
  PRESSURE = 0.1,
  PRESSURE_ITERATIONS = 20,
  CURL = 3,
  SPLAT_RADIUS = 0.2,
  SPLAT_FORCE = 6000,
  SHADING = true,
  COLOR_UPDATE_SPEED = 10,
  BACK_COLOR = { r: 0.341, g: 0.698, b: 0.714 },
  TRANSPARENT = false
}) {
  const canvasRef = useRef(null);

  // Gradient endpoints normalized
  const GRADIENT_START = { r: 87/255, g: 178/255, b: 182/255 };
  const GRADIENT_END   = { r: 1.0,      g: 1.0,     b: 1.0     };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // -- Utility functions
    function scaleByPixelRatio(val) {
      const ratio = window.devicePixelRatio || 1;
      return Math.floor(val * ratio);
    }
    function correctDeltaX(d) {
      const aspect = canvas.width / canvas.height;
      return aspect < 1 ? d * aspect : d;
    }
    function correctDeltaY(d) {
      const aspect = canvas.width / canvas.height;
      return aspect > 1 ? d / aspect : d;
    }
    function lerpColor(a, b, t) {
      return {
        r: a.r * (1 - t) + b.r * t,
        g: a.g * (1 - t) + b.g * t,
        b: a.b * (1 - t) + b.b * t
      };
    }
    function generateColor(pointer) {
      const t = pointer.texcoordX;
      return lerpColor(GRADIENT_START, GRADIENT_END, t);
    }

    // -- Pointer state
    function Pointer() {
      this.id = -1;
      this.texcoordX = 0;
      this.texcoordY = 0;
      this.prevX = 0;
      this.prevY = 0;
      this.deltaX = 0;
      this.deltaY = 0;
      this.down = false;
      this.moved = false;
      this.color = { r:0, g:0, b:0 };
    }
    const pointers = [ new Pointer() ];

    // -- Placeholder WebGL setup
    const { gl, ext } = getWebGLContext(canvas);
    // ... shaders, FBOs, programs, etc. ...

    // -- Splash routines
    function splat(x, y, dx, dy, color) {
      // existing splat implementation
    }
    function updateFrame() {
      // existing frame loop
      requestAnimationFrame(updateFrame);
    }

    // -- Event handlers
    function updateDown(p, id, x, y) {
      p.id = id;
      p.down = true;
      p.moved = false;
      p.texcoordX = x / canvas.width;
      p.texcoordY = 1 - y / canvas.height;
      p.prevX = p.texcoordX;
      p.prevY = p.texcoordY;
      p.deltaX = 0;
      p.deltaY = 0;
      p.color = generateColor(p);
    }
    function updateMove(p, x, y) {
      p.prevX = p.texcoordX;
      p.prevY = p.texcoordY;
      p.texcoordX = x / canvas.width;
      p.texcoordY = 1 - y / canvas.height;
      p.deltaX = correctDeltaX(p.texcoordX - p.prevX);
      p.deltaY = correctDeltaY(p.texcoordY - p.prevY);
      p.moved = Math.abs(p.deltaX) > 0 || Math.abs(p.deltaY) > 0;
      if (p.moved) p.color = generateColor(p);
    }
    function updateUp(p) {
      p.down = false;
    }
    function clickSplat(p) {
      const c = generateColor(p);
      c.r *= 10; c.g *= 10; c.b *= 10;
      const dx = 10 * (Math.random() - 0.5);
      const dy = 30 * (Math.random() - 0.5);
      splat(p.texcoordX, p.texcoordY, dx, dy, c);
    }

    window.addEventListener('mousedown', e => {
      const p = pointers[0];
      const x = scaleByPixelRatio(e.clientX);
      const y = scaleByPixelRatio(e.clientY);
      updateDown(p, -1, x, y);
      clickSplat(p);
    });
    window.addEventListener('mousemove', e => {
      const p = pointers[0];
      const x = scaleByPixelRatio(e.clientX);
      const y = scaleByPixelRatio(e.clientY);
      updateMove(p, x, y);
    });
    window.addEventListener('mouseup', () => updateUp(pointers[0]));

    // -- Start
    updateFrame();

  }, [
    SIM_RESOLUTION, DYE_RESOLUTION, CAPTURE_RESOLUTION,
    DENSITY_DISSIPATION, VELOCITY_DISSIPATION,
    PRESSURE, PRESSURE_ITERATIONS, CURL,
    SPLAT_RADIUS, SPLAT_FORCE, SHADING,
    COLOR_UPDATE_SPEED, BACK_COLOR, TRANSPARENT
  ]);

  return (
    <div style={{ position:'fixed', top:0, left:0, zIndex:50, pointerEvents:'none', width:'100%', height:'100%' }}>
      <canvas ref={canvasRef} id="fluid" style={{ width:'100vw', height:'100vh', display:'block' }} />
    </div>
  );
}
